  val segmentTree = new SegmentTree(popcountDepth, (a, b) => a + b)

  val answer = mutable.ArrayBuffer[Long]()

  for (query <- queries) {
    if (query(0) == 1) {
      // Query type 1: count numbers with popcount-depth equal to k in [l, r]
      val l = query(1).toInt
      val r = query(2).toInt
      val k = query(3).toInt
      val count = segmentTree.rangeQuery(l, r, k)
      answer += count
    } else {
      // Query type 2: update nums[idx] to val
      val idx = query(1).toInt
      val val = query(2).toLong
      nums(idx) = val
      // Update the popcount-depth for the updated index
      val newDepth = popcountDepth(idx)
      // Update the segment tree
      segmentTree.update(idx, newDepth)
    }
  }

  answer.toArray
}

def popcount(n: Long): Int = {
  var count = 0
  while (n > 0) {
    n &= n - 1
    count += 1
  }
  count
}

class SegmentTree(val data: Array[Int], val combine: (Int, Int) => Int) {
  val n = data.length
  val tree = new Array[Int](4 * n)
  val lazy = new Array[Int](4 * n)

  def build(node: Int, l: Int, r: Int): Unit = {
    if (l == r) {
      tree(node) = data(l)
      return
    }
    val mid = (l + r) >> 1
    build(2 * node + 1, l, mid)
    build(2 * node + 2, mid + 1, r)
    tree(node) = combine(tree(2 * node + 1), tree(2 * node + 2))
  }

  def update(pos: Int, value: Int): Unit = {
    _update(0, 0, n - 1, pos, value)
  }

  private def _update(node: Int, l: Int, r: Int, pos: Int, value: Int): Unit = {
    if (l == r) {
      tree(node) = value
      return
    }
    val mid = (l + r) >> 1
    if (pos <= mid) {
      _update(2 * node + 1, l, mid, pos, value)
    } else {
      _update(2 * node + 2, mid + 1, r, pos, value)
    }
    tree(node) = combine(tree(2 * node + 1), tree(2 * node + 2))
  }

  def rangeQuery(l: Int, r: Int, k: Int): Int = {
    _rangeQuery(0, 0, n - 1, l, r, k)
  }

  private def _rangeQuery(node: Int, nodeL: Int, nodeR: Int, l: Int, r: Int, k: Int): Int = {
    if (nodeR < l || nodeL > r) {
      return 0
    }
    if (l <= nodeL && nodeR <= r) {
      return tree(node)
    }
    val mid = (nodeL + nodeR) >> 1
    return _rangeQuery(2 * node + 1, nodeL, mid, l, r, k) + _rangeQuery(2 * node + 2, mid + 1, nodeR, l, r, k)
  }

  // Initialize the segment tree
  build(0, 0, n - 1)
}
