import { SegmentTree } from './SegmentTree';

function solve(nums, queries) {
    // Precompute the popcount-depth for each number in nums
    const popcountDepth = nums.map(num => {
        let depth = 0;
        let current = num;
        while (current > 0) {
            current = popcount(current);
            depth++;
        }
        return depth;
    });

    // Create a segment tree for range queries
    const segmentTree = new SegmentTree(popcountDepth, (a, b) => a + b);

    const answer = [];

    for (const query of queries) {
        if (query[0] === 1) {
            // Query type 1: count numbers with popcount-depth equal to k in [l, r]
            const l = query[1];
            const r = query[2];
            const k = query[3];
            const count = segmentTree.rangeQuery(l, r, k);
            answer.push(count);
        } else {
            // Query type 2: update nums[idx] to val
            const idx = query[1];
            const val = query[2];
            nums[idx] = val;
            // Update the popcount-depth for the updated index
            const newDepth = popcountDepth[idx];
            // Update the segment tree
            segmentTree.update(idx, newDepth);
        }
    }

    return answer;
}

function popcount(n) {
    let count = 0;
    while (n > 0) {
        n &= n - 1;
        count++;
    }
    return count;
}

class SegmentTree {
    constructor(data, combine) {
        this.n = data.length;
        this.combine = combine;
        this.tree = new Array(4 * this.n).fill(0);
        this.build(0, 0, this.n - 1, data);
    }

    build(node, l, r, data) {
        if (l === r) {
            this.tree[node] = data[l];
            return;
        }
        const mid = (l + r) >> 1;
        this.build(2 * node + 1, l, mid, data);
        this.build(2 * node + 2, mid + 1, r, data);
        this.tree[node] = this.combine(this.tree[2 * node + 1], this.tree[2 * node + 2]);
    }

    update(pos, value) {
        this._update(0, 0, this.n - 1, pos, value);
    }

    _update(node, l, r, pos, value) {
        if (l === r) {
            this.tree[node] = value;
            return;
        }
        const mid = (l + r) >> 1;
        if (pos <= mid) {
            this._update(2 * node + 1, l, mid, pos, value);
        } else {
            this._update(2 * node + 2, mid + 1, r, pos, value);
        }
        this.tree[node] = this.combine(this.tree[2 * node + 1], this.tree[2 * node + 2]);
    }

    rangeQuery(l, r, k) {
        return this._rangeQuery(0, 0, this.n - 1, l, r, k);
    }

    _rangeQuery(node, nodeL, nodeR, l, r, k) {
        if (nodeR < l || nodeL > r) {
            return 0;
        }
        if (l <= nodeL && nodeR <= r) {
            return this.tree[node];
        }
        const mid = (nodeL + nodeR) >> 1;
        return this._rangeQuery(2 * node + 1, nodeL, mid, l, r, k) + this._rangeQuery(2 * node + 2, mid + 1, nodeR, l, r, k);
    }
}
